ax3 = fig.add_subplot(gs[0, 2])  # Facts panel

# Row 2
ax4 = fig.add_subplot(gs[1, 0])  # Map
ax5 = fig.add_subplot(gs[1, 1])  # Timeline (wider)
ax6 = fig.add_subplot(gs[1, 2])  # Fireballs

# Style all axes
for ax in [ax1, ax2, ax3, ax4, ax5, ax6]:
    ax.set_facecolor(CREAM)
    for spine in ax.spines.values():
        spine.set_edgecolor(GOLD)
        spine.set_linewidth(2)

# Draw content
print("Drawing Dunnottar Castle illustration...")
draw_dunnottar_castle(ax1)

print("Drawing Stonehaven Harbour illustration...")
draw_harbour(ax2)

print("Drawing facts panel...")
draw_facts_panel(ax3)

print("Drawing location map...")
draw_map_sketch(ax4)

print("Drawing historical timeline...")
draw_timeline(ax5)

print("Drawing Fireballs ceremony illustration...")
draw_fireballs(ax6)

# Footer
fig.text(0.5, 0.015,
         'Sources: VisitScotland | Undiscovered Scotland | Wikipedia | National Library of Scotland',
         fontsize=8, ha='center', va='bottom', color='#aaaaaa',
         style='italic', transform=fig.transFigure)

plt.savefig('stonehaven_display.png', dpi=150, bbox_inches='tight',
            facecolor=DARK_BLUE, edgecolor='none')
